Part 7: Handling Response Metadata and Status Codes
Let’s explore what happens when things go wrong:

# Try requesting a resource that doesn't exist
bad_url &lt;- "https://jsonplaceholder.typicode.com/users/999999"

req &lt;- request(bad_url)
response &lt;- req_perform(req)

# Check the status
cat("Status code:", resp_status(response), "\n")


# Build a robust request handler
safe_get &lt;- function(url) {
  req &lt;- request(url)
  response &lt;- req_perform(req)
  status &lt;- resp_status(response)

  if (status == 200) {
    cat("Success! Status:", status, "\n")
    return(resp_body_json(response))
  } else if (status &gt;= 400 & status &lt; 500) {
    cat("Client error! Status:", status, "- Check your URL or parameters.\n")
    return(NULL)
  } else if (status &gt;= 500) {
    cat("Server error! Status:", status, "- The server has an issue.\n")
    return(NULL)
  }
}

# Test it
result &lt;- safe_get("https://jsonplaceholder.typicode.com/users/1")

Part 2: Building a Reusable Function
Let’s wrap the logic above into a clean, reusable function:

prev_weather &lt;- function(city, days) {

  # --- Geocoding ---
  geo_url &lt;- glue(
    "http://api.openweathermap.org/geo/1.0/direct?",
    "q=", URLencode(city),
    "&limit=1&appid=", Sys.getenv("API_KEY")
  )

  geo_response &lt;- req_perform(request(geo_url))

  if (resp_status(geo_response) != 200) {
    stop("Geocoding failed. Check your API key or city name.")
  }

  geo_data_df &lt;- resp_body_json(geo_response) |&gt; as.data.frame()

  if (length(geo_data_df) == 0) {
    stop("City not found. Please check the city name.")
  }

  lat &lt;- round(geo_data_df$lat, digits = 2)
  lon &lt;- round(geo_data_df$lon, digits = 2)
  cat("Coordinates for", city, "-&gt; Lat:", lat, "Lon:", lon, "\n")

  # --- Historical Weather ---
  date_range &lt;- as.character(lubridate::today() - days(1:days))
  hist_weather_df &lt;- data.frame()

  for (date in date_range) {
    weather_url &lt;- glue(
      "https://api.openweathermap.org/data/3.0/onecall/day_summary?",
      "lat=", lat,
      "&lon=", lon,
      "&date=", date,
      "&appid=", Sys.getenv("API_KEY"),
      "&units=imperial"
    )

    weather_response &lt;- req_perform(request(weather_url))

    if (resp_status(weather_response) == 200) {
      daily_weather_df &lt;- resp_body_json(weather_response) |&gt;
        as.data.frame() |&gt;
        mutate(city = city, date = date)

      hist_weather_df &lt;- bind_rows(hist_weather_df, daily_weather_df)
    } else {
      warning(paste("Failed to get weather for", date, "-", resp_status(weather_response)))
    }
  }

  return(hist_weather_df)
}


Test the Function

# Get past 4 days of weather for your city
prev_weather("San Luis Obispo", 4)


# Try another city!
prev_weather("Ames, IA, USA", 4)


